(function($) {
'use strict';
const VH360NotificationPreferences = {
init: function() {
this.container = $('.vh360-notification-preferences-container');
this.loadingEl = this.container.find('.vh360-notification-preferences-loading');
this.contentEl = this.container.find('.vh360-notification-preferences-content');
if (this.container.length) {
this.loadPreferences();
}
},
loadPreferences: function() {
const self = this;
$.ajax({
url: vh360NotificationPreferences.ajaxurl,
type: 'POST',
data: {
action: 'vh360_get_notification_preferences',
nonce: vh360NotificationPreferences.nonce
},
dataType: 'json',
success: function(response) {
self.loadingEl.hide();
if (response.success && response.data.preferences) {
self.renderPreferences(response.data.preferences, response.data.types);
self.bindEvents();
} else {
self.showError();
}
},
error: function() {
self.loadingEl.hide();
self.showError();
}
});
},
renderPreferences: function(preferences, types) {
const escapeHtml = function(text) {
const div = document.createElement('div');
div.textContent = text;
return div.innerHTML;
};
const html = `
<div class="vh360-notification-preferences-form">
<!-- Enable/Disable Notifications -->
<div class="vh360-form-group">
<label class="vh360-checkbox-label vh360-notification-pref-main">
<input type="checkbox" name="notifications_enabled" value="1" ${preferences.enabled ? 'checked' : ''}>
<span><strong>${escapeHtml(vh360NotificationPreferences.strings.enableNotifications)}</strong></span>
</label>
<p class="vh360-form-help">${escapeHtml(vh360NotificationPreferences.strings.enableHelp)}</p>
</div>
<!-- Notification Frequency -->
<div class="vh360-form-group">
<label for="notification_frequency" class="vh360-form-label">${escapeHtml(vh360NotificationPreferences.strings.frequency)}</label>
<select name="notification_frequency" id="notification_frequency" class="vh360-form-input">
<option value="all" ${preferences.frequency === 'all' ? 'selected' : ''}>${escapeHtml(vh360NotificationPreferences.strings.frequencyAll)}</option>
<option value="important_only" ${preferences.frequency === 'important_only' ? 'selected' : ''}>${escapeHtml(vh360NotificationPreferences.strings.frequencyImportant)}</option>
<option value="digest_only" ${preferences.frequency === 'digest_only' ? 'selected' : ''}>${escapeHtml(vh360NotificationPreferences.strings.frequencyDigest)}</option>
</select>
<p class="vh360-form-help">${escapeHtml(vh360NotificationPreferences.strings.frequencyHelp)}</p>
</div>
<!-- Notification Types -->
<div class="vh360-form-group">
<label class="vh360-form-label">${escapeHtml(vh360NotificationPreferences.strings.notificationTypes)}</label>
<div class="vh360-notification-types-list">
${this.renderTypeCheckboxes(preferences.types, types)}
</div>
</div>
<!-- Display Settings -->
<div class="vh360-form-group">
<label class="vh360-form-label">${escapeHtml(vh360NotificationPreferences.strings.displaySettings)}</label>
<div class="vh360-notification-display-settings">
<label class="vh360-checkbox-label">
<input type="checkbox" name="notification_sound" value="1" ${preferences.display.sound ? 'checked' : ''}>
<span>${escapeHtml(vh360NotificationPreferences.strings.soundEnabled)}</span>
</label>
<label class="vh360-checkbox-label">
<input type="checkbox" name="notification_desktop" value="1" ${preferences.display.desktop ? 'checked' : ''}>
<span>${escapeHtml(vh360NotificationPreferences.strings.desktopEnabled)}</span>
</label>
<div class="vh360-notification-max-keep">
<label for="notification_max_keep" class="vh360-form-label">${escapeHtml(vh360NotificationPreferences.strings.maxKeep)}</label>
<input type="number" name="notification_max_keep" id="notification_max_keep" class="vh360-form-input vh360-form-input-small" value="${parseInt(preferences.display.max_keep, 10)}" min="10" max="1000" step="10">
<p class="vh360-form-help">${escapeHtml(vh360NotificationPreferences.strings.maxKeepHelp)}</p>
</div>
</div>
</div>
<!-- Save Button -->
<div class="vh360-form-actions">
<button type="button" class="vh360-dashboard-btn vh360-save-notification-preferences">
${escapeHtml(vh360NotificationPreferences.strings.savePreferences)}
</button>
</div>
</div>
`;
this.contentEl.html(html).show();
},
renderTypeCheckboxes: function(types, typeList) {
let html = '';
const escapeHtml = function(text) {
const div = document.createElement('div');
div.textContent = text;
return div.innerHTML;
};
const typeLabels = {
'follow': vh360NotificationPreferences.strings.typeFollow,
'like': vh360NotificationPreferences.strings.typeLike,
'comment': vh360NotificationPreferences.strings.typeComment,
'reply': vh360NotificationPreferences.strings.typeReply,
'mention': vh360NotificationPreferences.strings.typeMention,
'share': vh360NotificationPreferences.strings.typeShare
};
for (let i = 0; i < typeList.length; i++) {
const type = escapeHtml(typeList[i]);
const isChecked = types[typeList[i]] ? 'checked' : '';
const label = typeLabels[typeList[i]] ? escapeHtml(typeLabels[typeList[i]]) : type;
html += `
<label class="vh360-checkbox-label">
<input type="checkbox" name="notification_type_${type}" value="1" ${isChecked}>
<span>${label}</span>
</label>
`;
}
return html;
},
bindEvents: function() {
const self = this;
$(document).on('click', '.vh360-save-notification-preferences', function(e) {
e.preventDefault();
self.savePreferences();
});
},
savePreferences: function() {
const self = this;
const $btn = $('.vh360-save-notification-preferences');
const originalText = $btn.text();
const preferences = {
enabled: $('input[name="notifications_enabled"]').is(':checked'),
frequency: $('#notification_frequency').val(),
types: {},
display: {
sound: $('input[name="notification_sound"]').is(':checked'),
desktop: $('input[name="notification_desktop"]').is(':checked'),
max_keep: parseInt($('#notification_max_keep').val(), 10)
}
};
$('[name^="notification_type_"]').each(function() {
const type = $(this).attr('name').replace('notification_type_', '');
preferences.types[type] = $(this).is(':checked');
});
$btn.prop('disabled', true).text(vh360NotificationPreferences.strings.saving);
$.ajax({
url: vh360NotificationPreferences.ajaxurl,
type: 'POST',
data: {
action: 'vh360_update_notification_preferences',
nonce: vh360NotificationPreferences.nonce,
preferences: preferences
},
dataType: 'json',
success: function(response) {
$btn.prop('disabled', false).text(originalText);
if (response.success) {
self.showNotification(response.data.message || vh360NotificationPreferences.strings.preferencesSaved, 'success');
} else {
self.showNotification(response.data.message || vh360NotificationPreferences.strings.error, 'error');
}
},
error: function() {
$btn.prop('disabled', false).text(originalText);
self.showNotification(vh360NotificationPreferences.strings.error, 'error');
}
});
},
showError: function() {
this.contentEl.html(`
<div class="vh360-notification-preferences-error">
<p>${vh360NotificationPreferences.strings.loadError}</p>
</div>
`).show();
},
showNotification: function(message, type) {
if (typeof VH360Dashboard !== 'undefined' && VH360Dashboard.showNotification) {
VH360Dashboard.showNotification(message, type);
} else {
const $notification = $(`
<div class="vh360-notification-message vh360-notification-${type}">
${message}
</div>
`);
$('#vh360-notification-preferences').prepend($notification);
setTimeout(function() {
$notification.fadeOut(function() {
$(this).remove();
});
}, 3000);
}
}
};
$(document).ready(function() {
if ($('#settings').hasClass('active')) {
VH360NotificationPreferences.init();
}
$(document).on('click', '[data-tab="settings"]', function() {
if (!VH360NotificationPreferences.container || VH360NotificationPreferences.container.length === 0) {
setTimeout(function() {
VH360NotificationPreferences.init();
}, 100);
}
});
});
})(jQuery);
